function mou_details_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('mou_details_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'type' => Request::val('type', ''),
		'company_name' => br2nl(Request::val('company_name', '')),
		'objective_of_mou' => br2nl(Request::val('objective_of_mou', '')),
		'agreement_period' => Request::val('agreement_period', ''),
		'date_of_agreement' => Request::dateComponents('date_of_agreement', ''),
		'date_of_expiry' => Request::dateComponents('date_of_expiry', ''),
		'status' => Request::val('status', ''),
		'point_of_contact' => Request::val('point_of_contact', ''),
		'contact_number' => Request::val('contact_number', ''),
		'contact_email_id' => Request::val('contact_email_id', ''),
		'website_link' => Request::val('website_link', ''),
		'country' => Request::val('country', ''),
		'assigned_mou_to' => Request::lookup('assigned_mou_to', ''),
		'upload_mou' => Request::fileUpload('upload_mou', [
			'maxSize' => 10240000,
			'types' => 'txt|doc|docx|docm|odt|pdf|rtf',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('mou_details_table', 'upload_mou', Request::val('SelectedID'));
			},
		]),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('mou_details_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		mou_details_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function mou_details_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function mou_details_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('mou_details_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: mou_details_table_before_delete
	if(function_exists('mou_details_table_before_delete')) {
		$args = [];
		if(!mou_details_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `mou_details_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: mou_details_table_after_delete
	if(function_exists('mou_details_table_after_delete')) {
		$args = [];
		mou_details_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='mou_details_table' AND `pkValue`='{$selected_id}'", $eo);
}

function mou_details_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('mou_details_table', $selected_id, 'edit')) return false;

	$data = [
		'type' => Request::val('type', ''),
		'company_name' => br2nl(Request::val('company_name', '')),
		'objective_of_mou' => br2nl(Request::val('objective_of_mou', '')),
		'agreement_period' => Request::val('agreement_period', ''),
		'date_of_agreement' => Request::dateComponents('date_of_agreement', ''),
		'date_of_expiry' => Request::dateComponents('date_of_expiry', ''),
		'status' => Request::val('status', ''),
		'point_of_contact' => Request::val('point_of_contact', ''),
		'contact_number' => Request::val('contact_number', ''),
		'contact_email_id' => Request::val('contact_email_id', ''),
		'website_link' => Request::val('website_link', ''),
		'country' => Request::val('country', ''),
		'assigned_mou_to' => Request::lookup('assigned_mou_to', ''),
		'upload_mou' => Request::fileUpload('upload_mou', [
			'maxSize' => 10240000,
			'types' => 'txt|doc|docx|docm|odt|pdf|rtf',
			'noRename' => false,
			'dir' => '',
			'id' => $selected_id,
			'success' => function($name, $selected_id) {
			},
			'removeOnRequest' => true,
			'remove' => function($selected_id) {
				// do nothing: preserve removed files on server.
			},
			'failure' => function($selected_id, $fileRemoved) {
				if($fileRemoved) return '';
				return existing_value('mou_details_table', 'upload_mou', $selected_id);
			},
		]),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('mou_details_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: mou_details_table_before_update
	if(function_exists('mou_details_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!mou_details_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'mou_details_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="mou_details_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('mou_details_table', $data['selectedID'], calculated_fields()['mou_details_table']);

	// hook: mou_details_table_after_update
	if(function_exists('mou_details_table_after_update')) {
		if($row = getRecord('mou_details_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!mou_details_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('mou_details_table', $selected_id);
}

